class _ListMountainArray(MountainArray):
    def __init__(self, arr: list[int]) -> None:
        self._arr = arr
        self.calls = 0

    def get(self, index: int) -> int:
        self.calls += 1
        if self.calls > 100:
            raise RuntimeError("Exceeded 100 MountainArray.get() calls")
        return self._arr[index]

    def length(self) -> int:
        return len(self._arr)

